const GSP_STAGE_STYLES = {
  "Strategic Planning":  { color: "#c04520", fillColor: "#F37045", fillOpacity: 0.35, weight: 2 },
  "Option Planning":     { color: "#c89500", fillColor: "#FEC00F", fillOpacity: 0.35, weight: 2 },
  "Concept Planning":    { color: "#2878a8", fillColor: "#45A4DB", fillOpacity: 0.35, weight: 2 },
  "Design & Deliver":    { color: "#2d8545", fillColor: "#46B965", fillOpacity: 0.35, weight: 2 },
};
function addGSPLayer(map) {
  return L.geoJSON(GSP_WSA_SW_WW, {
    style: f => GSP_STAGE_STYLES[f.properties.planning_stage] || { color: "#666", fillOpacity: 0.2 },
    onEachFeature: (f, layer) => {
      const p = f.properties;
      const fy = p.fy_timeline ? `<br>Timeline: ${p.fy_timeline}` : '';
      layer.bindPopup(`<strong>${p.precinct_name}</strong><br>Stage: ${p.planning_stage}${fy}<br>Area: ${p.area_sqkm} km\u00b2`);
      layer.bindTooltip(p.precinct_name + (p.fy_timeline ? ' \u2014 ' + p.fy_timeline : ''), { sticky: true });
    }
  });
}
if (typeof module !== 'undefined') module.exports = { GSP_WSA_SW_WW, GSP_STAGE_STYLES, addGSPLayer };
